- "total placements" refers to the total number of students who secured jobs;
- "faculty strength" refers to the total number of faculty members;
- "student performance" refers to the number of students who passed.

sql:
SELECT year_id, SUM(reopened_institutions) AS total_reopened
FROM institution_counts
GROUP BY year_id;

SELECT students_passed 
FROM student_performance 
WHERE performance_id = 1;

SELECT AVG(average_salary) AS average_international_placement_salary
FROM placement_statistics
WHERE students_placed_internationally > 0;

external_knowledge:
- 'blossomed' refers to institutions that have the most recent performance data;
- 'success is measured by the number of students who have passed exceeding the average success rate' means the `students_passed` count is greater than the average `students_passed` across all institutions;
- 'thriving educational gardens' refers to institutions with the most recent data and above-average success rates.

sql:
SELECT COUNT(DISTINCT institution_id)
FROM institution_yearly_data
WHERE total_intake > 1000 AND students_passed > 500;

SELECT COUNT(DISTINCT institution_id) 
FROM institution_yearly_data 
WHERE year_id = 1 AND total_intake > (SELECT AVG(total_intake) FROM institution_yearly_data WHERE year_id = 1);

external_knowledge:
- 'Total institutions' refers to the number of educational institutions in a given academic year;
- 'Total intake' refers to the number of students enrolled in these institutions in a given academic year;
- 'Students passed' refers to the number of students who successfully completed their academic year;
- 'Students with honors' refers to the number of students who passed with a high level of distinction.

- `year_id` is a unique identifier for each academic year;
- `year_name` is a human-readable name for the academic year, such as "2012-13";
- `total_faculty` represents the total number of faculty members in all institutions for that year;
- `total_placements` represents the total number of job placements secured by students in that year;
- `students_passed` represents the total number of students who successfully passed their courses in that year;
- `total_institutions` represents the total number of educational institutions in that year.

sql:
SELECT total_institutions
FROM institution_counts ic
WHERE ic.year_id = (
  SELECT MIN(year_id) 
  FROM academic_years
);

SELECT 
  (SELECT AVG(total_intake) FROM student_enrollment) AS average_student_enrollment,
  (SELECT AVG(total_faculty) FROM faculty_strength) AS average_faculty_strength;

SELECT total_faculty, full_time_faculty
FROM faculty_strength
WHERE year_id = 0;

SELECT AVG(T1.institutions_with_expansion) AS average_expanded_institutions
FROM institution_counts T1
WHERE T1.total_institutions > (
  SELECT AVG(total_institutions)
  FROM institution_counts
);

SELECT COUNT(*) 
FROM institution_yearly_data 
WHERE total_intake > (SELECT AVG(total_intake) FROM institution_yearly_data);

